import { prisma } from "@/lib/prisma";
import { getSession } from "@/lib/session";
import { successResponse, errorResponse } from "@/lib/api-response";

// GET /api/appointments — list appointments (role-aware)
export async function GET(request: Request) {
  const session = await getSession();
  if (!session) return errorResponse("Unauthorized", 401);

  const { searchParams } = new URL(request.url);
  const status = searchParams.get("status");

  try {
    if (session.role === "PATIENT") {
      const patient = await prisma.patient.findUnique({ where: { userId: session.userId } });
      if (!patient) return errorResponse("Patient not found", 404);

      const appointments = await prisma.appointment.findMany({
        where: {
          patientId: patient.id,
          ...(status ? { status: status as any } : {}),
        },
        include: {
          doctor: { select: { name: true, specialization: true, photo: true } },
          hospital: { select: { name: true, city: true, phone: true } },
          slot: true,
        },
        orderBy: { createdAt: "desc" },
      });
      return successResponse({ appointments });
    }

    if (session.role === "HOSPITAL") {
      const hospital = await prisma.hospital.findUnique({ where: { userId: session.userId } });
      if (!hospital) return errorResponse("Hospital not found", 404);

      const appointments = await prisma.appointment.findMany({
        where: {
          hospitalId: hospital.id,
          ...(status ? { status: status as any } : {}),
        },
        include: {
          doctor: { select: { name: true, specialization: true } },
          patient: { select: { name: true, phone: true } },
          slot: true,
        },
        orderBy: { createdAt: "desc" },
      });
      return successResponse({ appointments });
    }

    return errorResponse("Forbidden", 403);
  } catch (e) {
    console.error(e);
    return errorResponse("Failed to fetch appointments", 500);
  }
}

// POST /api/appointments — patient books appointment
export async function POST(request: Request) {
  const session = await getSession();
  if (!session || session.role !== "PATIENT") return errorResponse("Unauthorized", 401);

  try {
    const body = await request.json();
    const { doctorId, hospitalId, slotId, type, reason } = body;

    if (!doctorId || !hospitalId || !slotId) return errorResponse("Missing required fields", 400);

    const patient = await prisma.patient.findUnique({ where: { userId: session.userId } });
    if (!patient) return errorResponse("Patient profile not found", 404);

    // Check slot is still available
    const slot = await prisma.slot.findUnique({ where: { id: slotId } });
    if (!slot || slot.status !== "AVAILABLE") return errorResponse("Slot is no longer available", 409);

    // Get doctor fee
    const doctor = await prisma.doctor.findUnique({ where: { id: doctorId } });
    if (!doctor) return errorResponse("Doctor not found", 404);

    const fee = type === "VIDEO_CALL" ? (doctor.consultationFee ?? 0) : (doctor.consultationFee ?? 0);

    const appointment = await prisma.$transaction(async (tx) => {
      // Mark slot as booked
      await tx.slot.update({ where: { id: slotId }, data: { status: "BOOKED" } });

      return tx.appointment.create({
        data: {
          patientId: patient.id,
          doctorId,
          hospitalId,
          slotId,
          type: type || "IN_PERSON",
          reason,
          fee,
          status: "PENDING",
        },
        include: {
          doctor: { select: { name: true, specialization: true } },
          hospital: { select: { name: true, city: true } },
          slot: true,
        },
      });
    });

    return successResponse({ appointment }, 201);
  } catch (e: any) {
    console.error(e);
    return errorResponse("Failed to book appointment", 500);
  }
}

// PATCH /api/appointments — update status (hospital confirms/cancels/completes)
export async function PATCH(request: Request) {
  const session = await getSession();
  if (!session) return errorResponse("Unauthorized", 401);

  try {
    const body = await request.json();
    const { appointmentId, status, notes } = body;

    if (!appointmentId || !status) return errorResponse("Missing fields", 400);

    const appointment = await prisma.appointment.findUnique({
      where: { id: appointmentId },
      include: { slot: true },
    });
    if (!appointment) return errorResponse("Appointment not found", 404);

    // Authorization check
    if (session.role === "HOSPITAL") {
      const hospital = await prisma.hospital.findUnique({ where: { userId: session.userId } });
      if (!hospital || hospital.id !== appointment.hospitalId) return errorResponse("Forbidden", 403);
    } else if (session.role === "PATIENT") {
      // Patients can only cancel
      if (status !== "CANCELLED") return errorResponse("Patients can only cancel appointments", 403);
    }

    const updated = await prisma.$transaction(async (tx) => {
      // If cancelling, free the slot
      if (status === "CANCELLED") {
        await tx.slot.update({ where: { id: appointment.slotId }, data: { status: "AVAILABLE" } });
      }
      return tx.appointment.update({
        where: { id: appointmentId },
        data: { status, notes },
        include: {
          doctor: { select: { name: true, specialization: true } },
          patient: { select: { name: true, phone: true } },
          slot: true,
        },
      });
    });

    return successResponse({ appointment: updated });
  } catch (e) {
    console.error(e);
    return errorResponse("Failed to update appointment", 500);
  }
}
